<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Algorithm Visualizer</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    background: #0d1117;
    color: #c9d1d9;
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 24px;
  }

  h1 {
    font-size: 1.6rem;
    font-weight: 600;
    margin-bottom: 20px;
    color: #58a6ff;
    letter-spacing: 0.5px;
  }

  #controls {
    display: flex;
    gap: 12px;
    margin-bottom: 24px;
    flex-wrap: wrap;
    justify-content: center;
  }

  button {
    background: #21262d;
    color: #c9d1d9;
    border: 1px solid #30363d;
    padding: 10px 24px;
    border-radius: 6px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, transform 0.1s;
    font-weight: 500;
  }

  button:hover {
    background: #30363d;
    border-color: #58a6ff;
  }

  button:active {
    transform: scale(0.97);
  }

  button:disabled {
    opacity: 0.4;
    cursor: not-allowed;
  }

  #sort { border-color: #238636; }
  #sort:hover:not(:disabled) { background: #238636; color: #fff; }

  #shuffle { border-color: #9e6a03; }
  #shuffle:hover:not(:disabled) { background: #9e6a03; color: #fff; }

  #reset { border-color: #da3633; }
  #reset:hover:not(:disabled) { background: #da3633; color: #fff; }

  #bars {
    display: flex;
    align-items: flex-end;
    justify-content: center;
    gap: 2px;
    width: 100%;
    max-width: 900px;
    height: 420px;
    background: #161b22;
    border: 1px solid #30363d;
    border-radius: 8px;
    padding: 12px 8px;
    overflow: hidden;
  }

  .bar {
    flex: 1;
    min-width: 3px;
    max-width: 40px;
    background: linear-gradient(180deg, #58a6ff 0%, #1f6feb 100%);
    border-radius: 2px 2px 0 0;
    transition: height 0.12s ease, background 0.12s ease, transform 0.08s ease;
    position: relative;
  }

  .bar.comparing {
    background: linear-gradient(180deg, #f0883e 0%, #d18616 100%);
    transform: scaleX(1.15);
  }

  .bar.swapping {
    background: linear-gradient(180deg, #f778ba 0%, #db61a2 100%);
    transform: scaleX(1.2);
  }

  .bar.sorted {
    background: linear-gradient(180deg, #3fb950 0%, #238636 100%);
  }

  #status {
    margin-top: 16px;
    font-size: 0.9rem;
    color: #8b949e;
    min-height: 1.4em;
  }

  #info {
    margin-top: 8px;
    font-size: 0.8rem;
    color: #484f58;
  }
</style>
</head>
<body>

<h1>Sorting Visualizer</h1>

<div id="controls">
  <button id="sort">▶ Sort</button>
  <button id="shuffle">⟳ Shuffle</button>
  <button id="reset">↺ Reset</button>
</div>

<div id="bars"></div>
<div id="status">Ready</div>
<div id="info">Algorithm: Merge Sort</div>

<script>
(function () {
  "use strict";

  const BARS_CONTAINER = document.getElementById("bars");
  const SORT_BTN = document.getElementById("sort");
  const SHUFFLE_BTN = document.getElementById("shuffle");
  const RESET_BTN = document.getElementById("reset");
  const STATUS = document.getElementById("status");

  const DEFAULT_SIZE = 50;
  const ANIMATION_DELAY = 18;

  let data = [];
  let originalData = [];
  let sortGenerator = null;
  let sorting = false;
  let sortDone = false;
  let animTimer = null;

  /* ── Merge Sort Generator ─────────────────────────────────── */

  function* mergeSortGenerator(arr) {
    const aux = new Array(arr.length);
    yield* _msort(arr, aux, 0, arr.length);
  }

  function* _msort(arr, aux, lo, hi) {
    if (hi - lo <= 1) return;
    const mid = Math.floor((lo + hi) / 2);
    yield* _msort(arr, aux, lo, mid);
    yield* _msort(arr, aux, mid, hi);
    yield* _merge(arr, aux, lo, mid, hi);
  }

  function* _merge(arr, aux, lo, mid, hi) {
    for (let i = lo; i < hi; i++) aux[i] = arr[i];

    let i = lo, j = mid, k = lo;
    while (i < mid && j < hi) {
      yield { type: "compare", i, j };
      if (aux[i] <= aux[j]) {
        arr[k] = aux[i];
        yield { type: "write", idx: k };
        i++;
      } else {
        arr[k] = aux[j];
        yield { type: "write", idx: k };
        j++;
      }
      k++;
    }
    while (i < mid) {
      arr[k] = aux[i];
      yield { type: "write", idx: k };
      i++;
      k++;
    }
    while (j < hi) {
      arr[k] = aux[j];
      yield { type: "write", idx: k };
      j++;
      k++;
    }
  }

  /* ── Rendering ────────────────────────────────────────────── */

  function renderBars(highlights) {
    highlights = highlights || {};
    const maxVal = Math.max(...data, 1);
    const containerHeight = BARS_CONTAINER.clientHeight - 24;

    BARS_CONTAINER.innerHTML = "";

    for (let i = 0; i < data.length; i++) {
      const bar = document.createElement("div");
      bar.className = "bar";
      const h = Math.max(4, (data[i] / maxVal) * containerHeight);
      bar.style.height = h + "px";

      if (highlights.comparing && (highlights.comparing === i)) {
        bar.classList.add("comparing");
      }
      if (highlights.sorted && highlights.sorted === i) {
        bar.classList.add("sorted");
      }

      BARS_CONTAINER.appendChild(bar);
    }
  }

  function renderAllSorted() {
    const maxVal = Math.max(...data, 1);
    const containerHeight = BARS_CONTAINER.clientHeight - 24;
    BARS_CONTAINER.innerHTML = "";
    for (let i = 0; i < data.length; i++) {
      const bar = document.createElement("div");
      bar.className = "bar sorted";
      const h = Math.max(4, (data[i] / maxVal) * containerHeight);
      bar.style.height = h + "px";
      BARS_CONTAINER.appendChild(bar);
    }
  }

  /* ── Core API ─────────────────────────────────────────────── */

  function isArraySorted(arr) {
    for (let i = 1; i < arr.length; i++) {
      if (arr[i] < arr[i - 1]) return false;
    }
    return true;
  }

  function shuffleArray(arr) {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
  }

  function generateRandomArray(size) {
    const arr = [];
    for (let i = 0; i < size; i++) {
      arr.push(Math.floor(Math.random() * 95) + 5);
    }
    return arr;
  }

  function stopAnimation() {
    if (animTimer) {
      clearTimeout(animTimer);
      animTimer = null;
    }
    sorting = false;
    SORT_BTN.disabled = false;
    SHUFFLE_BTN.disabled = false;
    RESET_BTN.disabled = false;
  }

  function startSortAnimation() {
    if (sorting || sortDone) return;
    sorting = true;
    SORT_BTN.disabled = true;
    SHUFFLE_BTN.disabled = true;
    RESET_BTN.disabled = true;
    STATUS.textContent = "Sorting...";

    function step() {
      const done = viz.sortStep();
      if (done) {
        sortDone = true;
        sorting = false;
        SORT_BTN.disabled = false;
        SHUFFLE_BTN.disabled = false;
        RESET_BTN.disabled = false;
        STATUS.textContent = "Sorted!";
        renderAllSorted();
        return;
      }
      animTimer = setTimeout(step, ANIMATION_DELAY);
    }
    animTimer = setTimeout(step, ANIMATION_DELAY);
  }

  /* ── Public API ───────────────────────────────────────────── */

  const viz = {
    array() {
      return data.slice();
    },

    setArray(a) {
      stopAnimation();
      data = a.slice();
      originalData = data.slice();
      sortGenerator = null;
      sortDone = false;
      sorting = false;
      STATUS.textContent = "Ready";
      renderBars();
    },

    sortStep() {
      if (sortDone) return true;

      if (!sortGenerator) {
        sortGenerator = mergeSortGenerator(data);
      }

      const result = sortGenerator.next();
      if (result.done) {
        sortDone = true;
        return true;
      }

      const step = result.value;

      if (step.type === "compare") {
        renderBars({ comparing: step.i });
      } else if (step.type === "write") {
        renderBars({ sorted: step.idx });
      }

      return false;
    },

    sorted() {
      return isArraySorted(data);
    }
  };

  window.viz = viz;

  /* ── Button Handlers ──────────────────────────────────────── */

  SORT_BTN.addEventListener("click", function () {
    if (viz.sorted()) {
      STATUS.textContent = "Already sorted!";
      return;
    }
    startSortAnimation();
  });

  SHUFFLE_BTN.addEventListener("click", function () {
    stopAnimation();
    shuffleArray(data);
    sortGenerator = null;
    sortDone = false;
    STATUS.textContent = "Shuffled";
    renderBars();
  });

  RESET_BTN.addEventListener("click", function () {
    stopAnimation();
    data = originalData.slice();
    sortGenerator = null;
    sortDone = false;
    STATUS.textContent = "Reset";
    renderBars();
  });

  /* ── Init ─────────────────────────────────────────────────── */

  data = generateRandomArray(DEFAULT_SIZE);
  originalData = data.slice();
  renderBars();

})();
</script>

</body>
</html>
